     1→//! Stage 1 (Observe): Execute a function with pre-generated inputs and collect
     2→//! execution traces. Pure observation — no Z3 or constraint solving.
     3→//!
     4→//! The observe module provides a composable building block: given a function and
     5→//! a list of inputs, it executes each input via the language frontend and returns
     6→//! structured trace data (branch coverage, line coverage, side effects, discovery
     7→//! attribution). Callers are responsible for generating inputs (random, boundary,
     8→//! user-provided) before calling into this module.
     9→//!
    10→//! ## Canonical execution primitive
    11→//!
    12→//! [`observe_single`] is the single source of truth for the execute → classify →
    13→//! track cycle. Both [`observe_batch`] and [`explorer::explore_function`] route
    14→//! through it, eliminating duplication and drift risk between random and batch
    15→//! observation paths.
    16→
    17→use std::collections::HashSet;
    18→use std::time::{Duration, Instant};
    19→
    20→use serde::{Deserialize, Serialize};
    21→
    22→use crate::protocol::SetupLevel;
    23→use crate::protocol::SetupContextStack;
    24→use crate::coverage_metrics::DiscoveryMethod;
    25→use crate::explorer::{
    26→    classify_error_intent, frontend_supports, path_hash, send_setup, send_teardown,
    27→    ExecutionSummary, ExploreError, LoopBuckets, ObservationOutput,
    28→};
    29→use crate::frontend::{Frontend, FrontendError};
    30→use crate::orchestrator::FrontendCapabilities;
    31→use crate::protocol::{
    32→    Command as ProtoCommand, ExecuteResult, FunctionAnalysis, MockConfig, ResponseResult,
    33→};
    34→
    35→/// Errors that can occur during observation.
    36→#[derive(Debug, thiserror::Error)]
    37→pub enum ObserveError {
    38→    #[error("frontend error: {0}")]
    39→    Frontend(#[from] FrontendError),
    40→    #[error("unexpected response from frontend: {0}")]
    41→    UnexpectedResponse(String),
    42→    #[error("instrumentation failed: {0}")]
    43→    InstrumentationFailed(String),
    44→}
    45→
    46→impl From<ExploreError> for ObserveError {
    47→    fn from(e: ExploreError) -> Self {
    48→        match e {
    49→            ExploreError::Frontend(fe) => Self::Frontend(fe),
    50→            ExploreError::UnexpectedResponse(msg) => Self::UnexpectedResponse(msg),
    51→        }
    52→    }
    53→}
    54→
    55→/// Configuration for the observe stage. Contains only execution-related settings;
    56→/// input generation is the caller's responsibility.
    57→#[derive(Debug, Clone)]
    58→pub struct ObserveConfig {
    59→    /// Path to the source file (needed for instrumentation).
    60→    pub file: String,
    61→    /// Mock configurations to pass to Execute commands.
    62→    pub mocks: Vec<MockConfig>,
    63→    /// Path to the setup file, if configured.
    64→    pub setup_file: Option<String>,
