    66→    pub setup_level: SetupLevel,
    67→    /// Frontend capabilities (used to gate setup/teardown commands).
    68→    pub capabilities: FrontendCapabilities,
    69→    /// Detected project root directory.
    70→    pub project_root: Option<String>,
    71→    /// Iteration count bucket boundaries for loop-aware path hashing.
    72→    pub loop_buckets: LoopBuckets,
    73→    /// Wall-clock timeout for the entire observation phase.
    74→    pub timeout: Option<Duration>,
    75→    /// Skip the Instrument command (caller already instrumented).
    76→    pub skip_instrument: bool,
    77→}
    78→
    79→impl From<&crate::explorer::ExploreConfig> for ObserveConfig {
    80→    fn from(ec: &crate::explorer::ExploreConfig) -> Self {
    81→        Self {
    82→            file: ec.file.clone(),
    83→            mocks: ec.mocks.clone(),
    84→            setup_file: ec.setup_file.clone(),
    85→            setup_level: ec.setup_level,
    86→            capabilities: ec.capabilities.clone(),
    87→            project_root: ec.project_root.clone(),
    88→            loop_buckets: ec.loop_buckets.clone(),
    89→            timeout: ec.timeout_explore,
