    92→    }
    93→}
    94→
    95→/// Raw observation results from executing a batch of inputs.
    96→/// Lighter-weight than `ObservationOutput` — no function metadata or summary.
    97→#[derive(Debug, Serialize, Deserialize)]
    98→pub struct BatchObservation {
    99→    /// Every execution result paired with its inputs and mock configs.
   100→    pub raw_results: Vec<(Vec<serde_json::Value>, Vec<MockConfig>, ExecuteResult)>,
   101→    /// Hashes of unique execution paths observed.
