   698→
   699→    /// Generate a random BranchDecision with a given branch_id.
   700→    fn arb_branch_decision(max_id: u32) -> impl Strategy<Value = BranchDecision> {
   701→        (0..max_id, any::<bool>()).prop_map(|(id, taken)| BranchDecision {
   702→            branch_id: id,
   703→            line: id * 10,
   704→            taken,
   705→            constraint: SymConstraint::Unknown {
   706→                hint: String::new(),
   707→            },
   708→        })
   709→    }
   710→
   711→    /// Generate a random ExecuteResult with up to `max_branches` branches.
   712→    fn arb_exec_result(max_branches: usize) -> impl Strategy<Value = ExecuteResult> {
   713→        let branches = proptest::collection::vec(arb_branch_decision(20), 0..max_branches);
   714→        let lines = proptest::collection::vec(1..200u32, 0..10);
   715→
   716→        (branches, lines).prop_map(|(branch_path, lines_executed)| ExecuteResult {
   717→            return_value: Some(serde_json::json!(0)),
   718→            thrown_error: None,
   719→            branch_path,
   720→            lines_executed,
   721→            calls_to_external: vec![],
   722→            path_constraints: vec![],
   723→            scope_events: vec![],
   724→            side_effects: vec![],
   725→            performance: PerformanceMetrics {
   726→                wall_time_ms: 1.0,
   727→                cpu_time_us: 1000,
   728→                heap_used_bytes: 0,
   729→                heap_allocated_bytes: 0,
   730→            },
   731→            capture_truncation: None,
   732→        })
   733→    }
   734→
   735→    proptest! {
   736→        /// The number of unique paths equals the number of distinct path_hash values.
   737→        #[test]
   738→        fn unique_paths_equals_distinct_hashes(
   739→            results in proptest::collection::vec(arb_exec_result(5), 1..20)
   740→        ) {
   741→            let buckets = LoopBuckets::none();
   742→            let mut seen: HashSet<u64> = HashSet::new();
   743→            for r in &results {
   744→                seen.insert(path_hash(r, &buckets));
   745→            }
   746→
   747→            // The HashSet invariant guarantees this; this test validates
   748→            // that path_hash is deterministic for equivalent results.
   749→            let mut seen2: HashSet<u64> = HashSet::new();
   750→            for r in &results {
   751→                seen2.insert(path_hash(r, &buckets));
   752→            }
   753→            prop_assert_eq!(seen, seen2);
   754→        }
   755→
   756→        /// Lines covered is the union of all lines_executed vectors.
   757→        #[test]
   758→        fn lines_covered_is_union(
   759→            results in proptest::collection::vec(arb_exec_result(3), 1..15)
   760→        ) {
   761→            let mut expected: HashSet<u32> = HashSet::new();
   762→            for r in &results {
   763→                for &line in &r.lines_executed {
   764→                    expected.insert(line);
   765→                }
   766→            }
   767→
   768→            // Simulate the observe loop's line tracking
   769→            let mut actual: HashSet<u32> = HashSet::new();
   770→            for r in &results {
   771→                for &line in &r.lines_executed {
   772→                    actual.insert(line);
   773→                }
   774→            }
   775→
   776→            prop_assert_eq!(expected, actual);
   777→        }
   778→
   779→        /// Each branch_id appears at most once in discoveries.
   780→        #[test]
   781→        fn discovery_branch_ids_unique(
   782→            results in proptest::collection::vec(arb_exec_result(5), 1..20)
   783→        ) {
   784→            let mut seen_branch_ids: HashSet<u32> = HashSet::new();
   785→            let mut discoveries: Vec<(u32, DiscoveryMethod)> = Vec::new();
   786→
   787→            for r in &results {
   788→                for decision in &r.branch_path {
   789→                    if seen_branch_ids.insert(decision.branch_id) {
   790→                        discoveries.push((decision.branch_id, DiscoveryMethod::Random));
   791→                    }
   792→                }
   793→            }
   794→
   795→            // No duplicate branch_ids
   796→            let ids: Vec<u32> = discoveries.iter().map(|(id, _)| *id).collect();
   797→            let unique_ids: HashSet<u32> = ids.iter().copied().collect();
   798→            prop_assert_eq!(ids.len(), unique_ids.len());
   799→        }
   800→
   801→        /// Coverage (lines_covered set size) is monotonically non-decreasing
   802→        /// as we process more execution results.
   803→        #[test]
   804→        fn coverage_monotonically_nondecreasing(
   805→            results in proptest::collection::vec(arb_exec_result(3), 1..15)
   806→        ) {
   807→            let mut all_lines: HashSet<u32> = HashSet::new();
   808→            let mut prev_count = 0usize;
   809→
   810→            for r in &results {
   811→                for &line in &r.lines_executed {
   812→                    all_lines.insert(line);
   813→                }
   814→                prop_assert!(all_lines.len() >= prev_count);
   815→                prev_count = all_lines.len();
   816→            }
   817→        }
   818→
   819→        /// ObserveState accumulates correctly across multiple results:
   820→        /// seen_paths grows monotonically, new_branch_ids are always genuinely new,
   821→        /// and all_lines is the union of all lines_executed.
   822→        #[test]
   823→        fn observe_state_accumulates_correctly(
   824→            results in proptest::collection::vec(arb_exec_result(5), 1..20)
   825→        ) {
   826→            let buckets = LoopBuckets::none();
   827→            let mut state = ObserveState::new();
   828→            let mut expected_lines: HashSet<u32> = HashSet::new();
   829→            let mut all_new_branch_ids: Vec<u32> = Vec::new();
   830→            let mut prev_paths_count = 0;
   831→
   832→            for r in &results {
   833→                let prev_branch_count = state.seen_branch_ids.len();
   834→
   835→                // Simulate observe_single's tracking logic
   836→                for &line in &r.lines_executed {
   837→                    state.all_lines.insert(line);
   838→                    expected_lines.insert(line);
   839→                }
   840→
   841→                let hash = path_hash(r, &buckets);
   842→                let is_new = state.seen_paths.insert(hash);
   843→
   844→                let mut new_ids = Vec::new();
   845→                for decision in &r.branch_path {
   846→                    if state.seen_branch_ids.insert(decision.branch_id) {
   847→                        new_ids.push(decision.branch_id);
   848→                    }
   849→                }
   850→
   851→                // Path count never decreases
   852→                prop_assert!(state.seen_paths.len() >= prev_paths_count);
   853→                prev_paths_count = state.seen_paths.len();
   854→
   855→                // New branch IDs are genuinely new
   856→                for &id in &new_ids {
   857→                    prop_assert!(!all_new_branch_ids.contains(&id),
   858→                        "branch_id {} discovered twice", id);
   859→                }
   860→                all_new_branch_ids.extend(new_ids);
   861→
   862→                // is_new correctly reflects whether the path was already seen
   863→                if is_new {
   864→                    prop_assert!(state.seen_paths.contains(&hash));
   865→                }
   866→            }
   867→
   868→            // Lines covered is exact union
   869→            prop_assert_eq!(&state.all_lines, &expected_lines);
   870→        }
   871→    }
   872→}
