    assert!(
        has_missing_at,
        "should discover 'missing @' path; found: {return_values:?}"
    );

    let has_valid = return_values
        .iter()
        .any(|v| v.contains("\"valid\":true") || v.contains("\"valid\": true"));
    assert!(
