            scope: "validateToken".to_string(),
            level: SetupLevel::Function,
            project_root: None,
            parent_context: None,
        })
        .await
        .expect("function setup failed");
    assert!(
        matches!(&resp_func.result, ResponseResult::Setup { .. }),
