    );

    let td_session = frontend
        .send(ProtoCommand::Teardown {
            scope: "test-session".to_string(),
            level: SetupLevel::Session,
        })
        .await
        .expect("session teardown failed");
    assert!(
        matches!(td_session.result, ResponseResult::TeardownAck),
